const generateMockAttendance = (staffList: Staff[]): AttendanceRecord[] => {
  const records: AttendanceRecord[] = [];
  const today = new Date();

  staffList.filter(s => s.status === 'ACTIVE').forEach(staff => {
    for (let i = 1; i < 7; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() - i);
      if (date.getDay() !== 0 && date.getDay() !== 6 && Math.random() > 0.1) {
        records.push({
           id: crypto.randomUUID(),
           staffId: staff.id,
           timestamp: new Date(date.setHours(8, 55 + Math.floor(Math.random()*15))).toISOString(),
           type: 'IN',
           status: Math.random() > 0.9 ? 'LATE' : 'NORMAL',
           photoUrl: `https://api.dicebear.com/7.x/avataaars/svg?seed=${staff.id}_${i}`
        });
      }
    }
  });
  return records;
};

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');

  const [staffList, setStaffList] = useState<Staff[]>(() => {
    const saved = localStorage.getItem('staffList');
    return saved ? JSON.parse(saved) : [...MOCK_STAFF_DATA, ...SPECIFIC_CANDIDATES, ...EXTRA_CANDIDATES];
  });

  const [queueData, setQueueData] = useState<QueueTicket[]>(() => {
    const saved = localStorage.getItem('queueData');
    return saved ? JSON.parse(saved) : MOCK_INITIAL_QUEUE;
  });

  const [announcements, setAnnouncements] = useState<Announcement[]>(() => {
    const saved = localStorage.getItem('announcements');
    return saved ? JSON.parse(saved) : MOCK_ANNOUNCEMENTS;
  });

  const [registrationList, setRegistrationList] = useState<RegistrationRecord[]>(() => {
    const saved = localStorage.getItem('registrationList');
    return saved ? JSON.parse(saved) : MOCK_REGISTRATION_DATA;
  });

  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>(() => {
    const saved = localStorage.getItem('attendanceRecords');
    return saved ? JSON.parse(saved) : [];
  });

  const [groups, setGroups] = useState<Group[]>(() => {
    const saved = localStorage.getItem('groups');
    return saved ? JSON.parse(saved) : MOCK_GROUPS;
  });

  const [forms, setForms] = useState<FormTemplate[]>(() => {
    const saved = localStorage.getItem('forms');
    return saved ? JSON.parse(saved) : MOCK_FORMS;
  });

  const [formSubmissions, setFormSubmissions] = useState<FormSubmission[]>(() => {
    const saved = localStorage.getItem('formSubmissions');
    return saved ? JSON.parse(saved) : [];
  });

  const [selectedFormId, setSelectedFormId] = useState<string | null>(null); 
  const [designerMode, setDesignerMode] = useState<'NONE' | 'EDIT' | 'ANALYTICS' | 'PREVIEW'>('NONE');
  const [systemDomain, setSystemDomain] = useState(() => localStorage.getItem('systemDomain') || 'https://workpulse.app');

  const [attendanceConfig, setAttendanceConfig] = useState<AttendanceConfig>(() => {
    const saved = localStorage.getItem('attendanceConfig');
    return saved ? JSON.parse(saved) : { startTime: '09:00', endTime: '18:00', overtimeStart: '19:00' };
  });

  useEffect(() => { localStorage.setItem('staffList', JSON.stringify(staffList)); }, [staffList]);
  useEffect(() => { localStorage.setItem('queueData', JSON.stringify(queueData)); }, [queueData]);
  useEffect(() => { localStorage.setItem('announcements', JSON.stringify(announcements)); }, [announcements]);
  useEffect(() => { localStorage.setItem('registrationList', JSON.stringify(registrationList)); }, [registrationList]);
  useEffect(() => { localStorage.setItem('attendanceRecords', JSON.stringify(attendanceRecords)); }, [attendanceRecords]);
  useEffect(() => { localStorage.setItem('groups', JSON.stringify(groups)); }, [groups]);
  useEffect(() => { localStorage.setItem('forms', JSON.stringify(forms)); }, [forms]);
  useEffect(() => { localStorage.setItem('formSubmissions', JSON.stringify(formSubmissions)); }, [formSubmissions]);
  useEffect(() => { localStorage.setItem('systemDomain', systemDomain); }, [systemDomain]);
  useEffect(() => { localStorage.setItem('attendanceConfig', JSON.stringify(attendanceConfig)); }, [attendanceConfig]);

  const [sidebarOpen, setSidebarOpen] = useState(false); // Default closed on mobile

  useEffect(() => {
    if (attendanceRecords.length === 0) {
       setAttendanceRecords(generateMockAttendance(staffList));
    }
  }, []);

  const handleLogin = (userId: string, role: 'ADMIN' | 'USER') => {
    if (role === 'ADMIN') {
      setSession({ userId, role });
      setActiveTab('dashboard');
    } else {
      const staff = staffList.find(s => s.id === userId);
      if (staff) {
        setSession({ userId, role, staff });
        setActiveTab(staff.status === 'PENDING' ? 'interview_status' : 'dashboard');
      }
    }
  };

  const handleLogout = () => {
    setSession(null);
    setActiveTab('dashboard');
  };

  const handleStaffClockIn = (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp: timestamp, // Use the captured timestamp from the child component
      type: 'IN',
      photoUrl,
      status
    };
    setAttendanceRecords([newRecord, ...attendanceRecords]);
  };

  const handleStaffClockOut = (photoUrl: string, status: AttendanceRecord['status'], timestamp: string) => {
    if (!session?.staff) return;
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: session.staff.id,
      timestamp: timestamp, // Use the captured timestamp from the child component
      type: 'OUT',
      photoUrl,
      status
    };
    setAttendanceRecords([newRecord, ...attendanceRecords]);
  };

  const handleQueueCheckIn = (staffId: string) => {
    if (queueData.some(t => t.staffId === staffId)) return;
    const staff = staffList.find(s => s.id === staffId);
    let name = staff?.name || '';
    if (!staff) {
       const reg = registrationList.find(r => r.id === staffId);
       if (reg) name = reg.name;
    }
    const newTicket: QueueTicket = {
      id: crypto.randomUUID(),
      ticketNumber: `A-${String(queueData.length + 1).padStart(3, '0')}`,
      staffId: staffId,
      staffName: name || '未知人员',
      status: 'WAITING',
      checkInTime: new Date().toISOString()
    };
    setQueueData(prev => [...prev, newTicket]);
    const photoUrl = staff?.avatar || `https://api.dicebear.com/7.x/avataaars/svg?seed=${staffId}`;
    const now = new Date();
    const currentTimeStr = now.toLocaleTimeString('en-GB', { hour12: false, hour: '2-digit', minute: '2-digit' });
    let status: AttendanceRecord['status'] = 'NORMAL';
    if (currentTimeStr > attendanceConfig.startTime) status = 'LATE';
    const newRecord: AttendanceRecord = {
      id: crypto.randomUUID(),
      staffId: staffId,
      timestamp: new Date().toISOString(),
      type: 'IN',
      photoUrl: photoUrl,
      status: status
    };
    setAttendanceRecords(prev => [...prev, newRecord]);
  };

  const updateTicketStatus = (ticketId: string, status: QueueTicket['status']) => {
    setQueueData(queueData.map(t => t.id === ticketId ? { ...t, status } : t));
  };

  const handleBatchAddStaffFromReg = (newStaffList: Staff[]) => {
    let count = 0;
    const updatedStaffList = [...staffList];
    newStaffList.forEach(newStaff => {
       const exists = updatedStaffList.some(s => 
          (s.idCard && s.idCard === newStaff.idCard) || 
          (s.phone && s.phone === newStaff.phone && s.name === newStaff.name)
       );
       if (!exists) {
         updatedStaffList.push(newStaff);
         count++;
       }
    });
    setStaffList(updatedStaffList);
    alert(`已成功将 ${count} 名新人员导入为正式员工/候选人，可直接登录系统。`);
  };

  const handleAddGroup = (group: Group) => setGroups([...groups, group]);
  const handleUpdateGroup = (group: Group) => setGroups(groups.map(g => g.id === group.id ? group : g));
  const handleDeleteGroup = (groupId: string) => setGroups(groups.filter(g => g.id !== groupId));
  const handleUpdateStaff = (staff: Staff) => setStaffList(staffList.map(s => s.id === staff.id ? staff : s));
  const handleAddStaff = (staff: Staff) => setStaffList([...staffList, staff]);

  const handleCreateForm = () => {
    // Generate dates for the schedule template
    const dates = [];
    for(let i=1; i<=3; i++) {
        const d = new Date();
        d.setDate(d.getDate() + i);
        dates.push(`${d.getMonth()+1}.${d.getDate()}`);
    }

    const newForm: FormTemplate = {
      id: crypto.randomUUID(),
      shareToken: crypto.randomUUID().slice(0, 8),
      title: '未命名人员登记表',
      description: '请填写真实信息以便录用。',
      status: 'ACTIVE', // Default active
      createdDate: new Date().toISOString().split('T')[0],
      submissionCount: 0,
      themeColor: 'blue',
      fields: [
        { id: crypto.randomUUID(), type: 'TEXT', label: '姓名', required: true, placeholder: '请输入真实姓名' },
        { id: crypto.randomUUID(), type: 'DATE', label: '出生日期', required: true },
        { id: crypto.randomUUID(), type: 'NUMBER', label: '年龄', required: true, placeholder: '请输入年龄' },
        { id: crypto.randomUUID(), type: 'GENDER', label: '性别', required: true, options: ['男', '女'] },
        { id: crypto.randomUUID(), type: 'PHONE', label: '手机号码', required: true, placeholder: '11位手机号' },
        { id: crypto.randomUUID(), type: 'EMAIL', label: '邮箱', required: false, placeholder: '选填' },
        { id: crypto.randomUUID(), type: 'ID_CARD', label: '身份证号码', required: true, placeholder: '用于身份核验' },
        { id: crypto.randomUUID(), type: 'SELECT', label: '开户行', required: true, options: ['工商银行', '建设银行', '农业银行', '中国银行', '招商银行', '其他银行'] },
        { id: crypto.randomUUID(), type: 'TEXT', label: '支行信息', required: true, placeholder: '例如：广州天河支行' },
        { id: crypto.randomUUID(), type: 'BANK_CARD', label: '银行卡账号', required: true, placeholder: '请输入卡号' },
        { id: crypto.randomUUID(), type: 'NOTES', label: '工作经历', required: false, placeholder: '请简述相关工作经验...' },
        { id: crypto.randomUUID(), type: 'SCHEDULE', label: '排班选择', required: true, config: { dates: dates } }
      ]
    };
    setForms([...forms, newForm]);
    setSelectedFormId(newForm.id);
    setDesignerMode('EDIT');
    setActiveTab('form_designer');
  };

  const handleToggleFormStatus = (formId: string, newStatus: 'ACTIVE' | 'CLOSED') => {
    setForms(forms.map(f => f.id === formId ? { ...f, status: newStatus } : f));
  };

  const handleDeleteForm = (id: string) => {
    if (confirm('确定要删除此表单吗？所有收集的数据也将被删除。')) {
      setForms(forms.filter(f => f.id !== id));
      setFormSubmissions(formSubmissions.filter(s => s.formId !== id));
    }
  };

  const handleDeleteSubmission = (submissionId: string) => {
    if (confirm('确定要删除这条提交记录吗？')) {
      setFormSubmissions(prev => prev.filter(s => s.id !== submissionId));
    }
  };

  const handleSaveForm = (updatedForm: FormTemplate) => {
    setForms(forms.map(f => f.id === updatedForm.id ? updatedForm : f));
  };

  const handleFormSubmit = (submission: FormSubmission) => {
    setFormSubmissions([...formSubmissions, submission]);
    setForms(forms.map(f => f.id === submission.formId ? { ...f, submissionCount: f.submissionCount + 1 } : f));
  };

  const handleSaveSettings = (settings: { domain: string, attendance: AttendanceConfig }) => {
    setSystemDomain(settings.domain);
    setAttendanceConfig(settings.attendance);
  };

  const handleNavigateToForm = (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => {
    setSelectedFormId(formId);
    setDesignerMode(mode);
    setActiveTab('form_designer');
  };

  const renderContent = () => {
    if (activeTab === 'form_designer' && selectedFormId) {
       const form = forms.find(f => f.id === selectedFormId);
       if (!form) return <div>Form not found</div>;
       if (designerMode === 'EDIT') return <FormDesigner form={form} onSave={handleSaveForm} onBack={() => setActiveTab('form_manager')} />;
       if (designerMode === 'ANALYTICS') return <FormAnalytics form={form} submissions={formSubmissions.filter(s => s.formId === form.id)} onBack={() => setActiveTab('form_manager')} onShare={() => setDesignerMode('PREVIEW')} />;
       if (designerMode === 'PREVIEW') return <FormShareDashboard form={form} onBack={() => setDesignerMode('ANALYTICS')} onPreview={() => setActiveTab('public_view_simulation')} customDomain={systemDomain} />; 
    }

    switch (activeTab) {
      case 'dashboard':
        if (session?.role === 'USER' && session?.staff) {
          const userGroup = groups.find(g => session.staff?.roles.some(r => r.groupId === g.id));
          const leader = staffList.find(s => s.roles.some(r => r.groupId === userGroup?.id && r.isLeader));
          const myAnnouncements = announcements.filter(a => !a.targetGroupId || a.targetGroupId === userGroup?.id);
          const myRecords = attendanceRecords.filter(r => r.staffId === session.staff?.id).sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
          const lastRecord = myRecords[0];
          const status = lastRecord?.type === 'IN' ? AttendanceStatus.CLOCKED_IN : AttendanceStatus.CLOCKED_OUT;

          return (
            <StaffDashboard 
              currentUser={session.staff}
              group={userGroup}
              leader={leader}
              announcements={myAnnouncements}
              attendanceStatus={status}
              attendanceHistory={myRecords.filter(r => new Date(r.timestamp).toDateString() === new Date().toDateString())}
              attendanceConfig={attendanceConfig}
              onClockIn={handleStaffClockIn}
              onClockOut={handleStaffClockOut}
            />
          );
        }
        return <Dashboard 
          attendanceRecords={attendanceRecords}
          queueData={queueData}
          announcements={announcements}
          isAdmin={session?.role === 'ADMIN'}
          groupInfo={session?.staff?.roles[0]}
          staffList={staffList}
          groups={groups}
          currentUser={session?.staff}
        />;

      case 'reports':
        // Determine visible groups based on role
        let visibleGroups = groups;
        if (session?.role === 'USER' && session.staff) {
           // For leaders: Only show groups where they are a leader
           const leaderGroupIds = session.staff.roles
             .filter(r => r.isLeader)
             .map(r => r.groupId);
           visibleGroups = groups.filter(g => leaderGroupIds.includes(g.id));
        }

        return <AttendanceReports 
          staffList={staffList} 
          groups={visibleGroups} 
          allRecords={attendanceRecords} 
          // If the user only has one group, we can optionally lock it, but giving the dropdown with 1 item is also fine.
          // fixedGroupId is no longer strictly necessary with the new filter logic, but helps UX if single group.
          fixedGroupId={visibleGroups.length === 1 ? visibleGroups[0].id : undefined} 
        />;
      case 'registration':
        return <StaffRegistration 
          records={registrationList} 
          onUpdateRecords={setRegistrationList} 
          groups={groups} 
          onBatchAddStaff={handleBatchAddStaffFromReg} 
          existingStaffList={staffList} 
          forms={forms} 
          formSubmissions={formSubmissions} 
          onManageForm={handleNavigateToForm} 
          onDeleteSubmission={handleDeleteSubmission}
        />;
      case 'training_checkin':
        return <TrainingCheckinManager 
          queue={queueData}
          registrationList={registrationList}
          staffList={staffList}
          forms={forms}
          formSubmissions={formSubmissions}
          onCheckIn={handleQueueCheckIn}
          onUpdateTicketStatus={updateTicketStatus}
          onClearQueue={() => setQueueData([])}
          onUpdateRegistration={setRegistrationList}
          onBatchAddStaff={handleBatchAddStaffFromReg}
          onManageForm={handleNavigateToForm}
        />;
      case 'form_manager':
        return <FormManager 
          forms={forms} 
          onCreateForm={handleCreateForm} 
          onDeleteForm={handleDeleteForm} 
          onSelectForm={(id, mode) => { setSelectedFormId(id); if (mode === 'SIMULATE') { setActiveTab('public_view_simulation'); } else { setDesignerMode(mode); setActiveTab('form_designer'); } }} 
          onToggleStatus={handleToggleFormStatus}
        />;
      case 'outsourced':
        return <OutsourcedManager staffList={staffList} groups={groups} onUpdateStaff={handleUpdateStaff} onAddStaff={handleAddStaff} onAddGroup={handleAddGroup} onUpdateGroup={handleUpdateGroup} onDeleteGroup={handleDeleteGroup} />;
      case 'talent':
        return <TalentPool staffList={staffList} registrationList={registrationList} onUpdateStaff={handleUpdateStaff} onUpdateRegistration={setRegistrationList} />;
      case 'announcements':
        return <AnnouncementManager currentUserRole={session?.role || 'USER'} currentUserGroups={session?.staff?.roles || []} announcements={announcements} onAddAnnouncement={(a) => setAnnouncements([a, ...announcements])} onDeleteAnnouncement={(id) => setAnnouncements(announcements.filter(a => a.id !== id))} currentUserName={session?.staff?.name || '管理员'} />;
      case 'settings':
        return <SystemSettings onSave={handleSaveSettings} initialDomain={systemDomain} initialAttendanceConfig={attendanceConfig} />;
      default:
        return <div className="p-10 text-center text-gray-500">功能开发中...</div>;
    }
  };

  if (activeTab === 'public_view_simulation' && selectedFormId) {
     const form = forms.find(f => f.id === selectedFormId);
     if (form) return <PublicDynamicForm form={form} onSubmit={handleFormSubmit} onCancel={() => { if (session) { if (designerMode === 'PREVIEW') setActiveTab('form_designer'); else setActiveTab('form_manager'); } else setActiveTab('login'); }} />;
  }

  if (!session) return <Login staffList={staffList} onLogin={handleLogin} />;

  const isLeader = session.role === 'USER' && session.staff?.roles.some(r => r.isLeader);

  // Helper to determine if full screen mode is active (Sidebar hidden)
  // Only hide sidebar in Form Designer EDIT mode. 
  // Analytics and Share (Preview) should keep the sidebar as requested.
  const isFullScreen = activeTab === 'form_designer' && designerMode === 'EDIT';

  return (
    <div className="flex min-h-screen bg-slate-50 text-gray-900 font-sans">

      {/* Desktop Sidebar (Hidden on Mobile) */}
      {!isFullScreen && (
        <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-white transition-transform duration-300 ease-in-out hidden lg:flex flex-col shadow-2xl`}>
          <div className="flex items-center justify-between p-6 border-b border-slate-800">
            <div className="flex items-center gap-3">
              <div className="bg-gradient-to-tr from-blue-500 to-purple-600 p-2 rounded-lg">
                <Layers size={24} className="text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold tracking-tight">WorkPulse</h1>
                <p className="text-xs text-slate-400">智能人力资源管理</p>
              </div>
            </div>
          </div>

          <nav className="flex-1 overflow-y-auto py-6 px-4 space-y-1 custom-scrollbar">
            {/* ADMIN NAV */}
            {session.role === 'ADMIN' && (
              <>
                 <div className="mb-6">
                    <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">管理中心</p>
                    <button onClick={() => setActiveTab('dashboard')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                      <LayoutDashboard size={20} /> <span className="font-medium">工作台</span>
                    </button>
                 </div>
                 <div className="mb-6">
                     <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">人员管理</p>
                     <button onClick={() => setActiveTab('training_checkin')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'training_checkin' || activeTab === 'registration' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <ClipboardCheck size={20} /> <span className="font-medium">现场报名 / 签到</span>
                     </button>
                     <button onClick={() => setActiveTab('outsourced')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'outsourced' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <Briefcase size={20} /> <span className="font-medium">分组与编外</span>
                     </button>
                     <button onClick={() => setActiveTab('talent')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'talent' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <Award size={20} /> <span className="font-medium">企业人才库</span>
                     </button>
                 </div>
                 <div className="mb-6">
                    <p className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">行政事务</p>
                    <button onClick={() => setActiveTab('announcements')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'announcements' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                      <Megaphone size={20} /> <span className="font-medium">公告通知</span>
                    </button>
                    <button onClick={() => setActiveTab('reports')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
