import React, { useState, useEffect, useMemo } from 'react';
import { Share2, Copy, Eye, QrCode, ExternalLink, ArrowLeft, FileText, Check, Download, Rocket, Link as LinkIcon, Printer, Clock, Calendar } from 'lucide-react';
import QRCode from 'qrcode';
import { FormTemplate } from '../types';

interface FormShareDashboardProps {
  form: FormTemplate; // Need full form object for ID/Token
  onBack: () => void;
  onPreview: () => void;
  customDomain: string;
}

const FormShareDashboard: React.FC<FormShareDashboardProps> = ({ form, onBack, onPreview, customDomain }) => {
  const [qrCodeUrl, setQrCodeUrl] = useState('');
  const [copied, setCopied] = useState(false);
  const [expiryDays, setExpiryDays] = useState<number | 'PERMANENT'>('PERMANENT'); // Validity state

  // Dynamic link generation
  const baseUrl = customDomain || "https://workpulse.app";

  const expirationDateStr = useMemo(() => {
    if (expiryDays === 'PERMANENT') return null;
    const date = new Date();
    date.setDate(date.getDate() + expiryDays);
    return date.toISOString().split('T')[0]; // YYYY-MM-DD
  }, [expiryDays]);

  const shareLink = useMemo(() => {
     let link = `${baseUrl}/f/${form.shareToken || form.id}`;
     if (expirationDateStr) {
        link += `?valid_until=${expirationDateStr}`;
     }
     return link;
  }, [baseUrl, form, expirationDateStr]);

  useEffect(() => {
    QRCode.toDataURL(shareLink, { width: 600, margin: 2, color: { dark: '#4338ca', light: '#ffffff' } })
      .then(url => setQrCodeUrl(url))
      .catch(err => console.error(err));
  }, [shareLink]);

  const handleCopy = () => {
    navigator.clipboard.writeText(shareLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownloadQR = () => {
    if (!qrCodeUrl) return;
    const link = document.createElement('a');
    link.href = qrCodeUrl;
    link.download = `QR_${form.title}_${expiryDays === 'PERMANENT' ? '永久' : expirationDateStr}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="flex flex-col h-full bg-gray-50/50">
      {/* Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-20">
         <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-lg text-gray-500 transition-colors">
               <ArrowLeft size={20} />
            </button>
            <div>
               <h1 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                 <Rocket size={20} className="text-indigo-600" /> 发布与分享
               </h1>
               <div className="flex items-center gap-2 text-xs text-gray-500 mt-0.5">
                  <span className={`w-2 h-2 rounded-full ${form.status === 'ACTIVE' ? 'bg-green-500' : 'bg-gray-300'}`}></span>
                  状态: {form.status === 'ACTIVE' ? '正在收集' : '停止收集'}
               </div>
            </div>
         </div>
      </div>

      <div className="flex-1 overflow-auto p-6 md:p-10">
         <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">

            {/* Left: Link & QR Actions */}
            <div className="space-y-6">
               {/* Link Card */}
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 hover:border-indigo-200 transition-colors group">
                  <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
                     <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><LinkIcon size={18} /></div>
                     公开链接
                  </h3>
                  <div className="p-4 bg-gray-50 rounded-xl border border-gray-200 flex items-center gap-3 mb-4 group-hover:bg-white transition-colors">
                     <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-center mb-1">
                           <p className="text-xs text-gray-400">
                              {expiryDays === 'PERMANENT' ? '永久链接' : `有效期至 ${expirationDateStr}`}
                           </p>
                        </div>
                        <p className="text-indigo-600 font-mono text-sm truncate font-medium">{shareLink}</p>
                     </div>
                  </div>
                  <div className="flex gap-3">
                     <button 
                       onClick={handleCopy}
                       className={`flex-1 py-2.5 rounded-xl font-bold text-sm transition-all flex items-center justify-center gap-2 ${
                          copied ? 'bg-green-600 text-white shadow-green-200' : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200 shadow-lg'
                       }`}
                     >
                       {copied ? <Check size={16} /> : <Copy size={16} />} {copied ? '已复制' : '复制链接'}
                     </button>
                     <button 
                       onClick={() => window.open(shareLink, '_blank')}
                       className="px-4 py-2.5 rounded-xl border border-gray-200 text-gray-600 hover:bg-gray-50 font-bold text-sm transition-colors"
                       title="在新窗口打开"
                     >
                       <ExternalLink size={18} />
                     </button>
                  </div>
               </div>

               {/* QR Card */}
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 flex flex-col gap-6">
                  <div className="flex flex-col sm:flex-row gap-6 items-center">
                     <div className="w-40 h-40 bg-white p-2 rounded-xl border-2 border-dashed border-gray-200 flex justify-center items-center shrink-0">
                        {qrCodeUrl ? (
                          <img src={qrCodeUrl} alt="QR Code" className="w-full h-full object-contain" />
                        ) : (
                          <div className="w-full h-full bg-gray-50 animate-pulse rounded-lg"></div>
                        )}
                     </div>
                     <div className="flex-1 w-full">
                        <h3 className="font-bold text-gray-800 mb-2 flex items-center gap-2">
                           <QrCode size={18} className="text-indigo-600" /> 专属二维码
                        </h3>
                        <p className="text-sm text-gray-500 mb-4 leading-relaxed">
                           扫码即可直接访问报名表。可下载打印在海报、工牌或传单上。
                        </p>

                        {/* Validity Selector */}
                        <div className="mb-4">
                           <label className="text-xs font-bold text-gray-400 uppercase mb-2 block flex items-center gap-1">
                              <Calendar size={12} /> 二维码有效期
                           </label>
                           <div className="flex gap-2 flex-wrap">
                              {[
                                 { label: '永久有效', val: 'PERMANENT' },
                                 { label: '7天', val: 7 },
                                 { label: '30天', val: 30 },
                                 { label: '24小时', val: 1 },
                              ].map(opt => (
                                 <button
                                    key={String(opt.val)}
                                    onClick={() => setExpiryDays(opt.val as any)}
                                    className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${
                                       expiryDays === opt.val 
                                          ? 'bg-indigo-50 border-indigo-200 text-indigo-600' 
                                          : 'bg-white border-gray-200 text-gray-500 hover:border-gray-300'
                                    }`}
                                 >
                                    {opt.label}
                                 </button>
                              ))}
                           </div>
                           {expiryDays !== 'PERMANENT' && (
                              <p className="text-[10px] text-orange-500 mt-2 flex items-center gap-1 bg-orange-50 w-fit px-2 py-1 rounded">
                                 <Clock size={10} /> 此二维码将于 {expirationDateStr} 失效
                              </p>
                           )}
                        </div>

                        <div className="flex gap-3">
                           <button 
                             onClick={handleDownloadQR}
                             className="flex-1 py-2.5 border border-gray-200 rounded-xl text-gray-700 hover:bg-gray-50 hover:text-indigo-600 text-sm font-bold transition-colors flex items-center justify-center gap-2"
                           >
                             <Download size={16} /> 下载 PNG
                           </button>
                           <button className="px-4 py-2.5 border border-gray-200 rounded-xl text-gray-500 hover:bg-gray-50 transition-colors hidden sm:block" title="打印">
                              <Printer size={18} />
                           </button>
                        </div>
                     </div>
                  </div>
               </div>
            </div>

            {/* Right: Visual Preview */}
            <div className="relative">
               <div className="sticky top-6">
                  <div className="bg-gradient-to-br from-gray-900 to-gray-800 rounded-[2.5rem] p-4 shadow-2xl border-4 border-gray-800 max-w-sm mx-auto transform rotate-1 hover:rotate-0 transition-transform duration-500">
                     <div className="bg-white rounded-[2rem] overflow-hidden h-[600px] relative border border-gray-200">
                        {/* Fake Browser Header */}
