import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  UserPlus, 
  Users, 
  ClipboardList, 
  TrendingUp,
  CalendarRange,
  PieChart,
  User,
  FileText,
  ShieldCheck,
  MapPin,
  BarChart3
} from 'lucide-react';
import { QueueTicket, RegistrationRecord, Staff, FormTemplate, FormSubmission } from '../types';
import StaffRegistration from './StaffRegistration';
import { ResponsiveContainer, PieChart as RePieChart, Pie, Cell, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

interface TrainingCheckinManagerProps {
  queue: QueueTicket[];
  registrationList: RegistrationRecord[];
  staffList: Staff[]; // Needed for legacy compatibility in sub-components
  forms: FormTemplate[];
  formSubmissions: FormSubmission[];
  onCheckIn: (staffId: string) => void;
  onUpdateTicketStatus: (ticketId: string, status: QueueTicket['status']) => void;
  onClearQueue: () => void;
  onUpdateRegistration: (records: RegistrationRecord[]) => void;
  onBatchAddStaff: (staffList: Staff[]) => void;
  onManageForm?: (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => void;
}

const TrainingCheckinManager: React.FC<TrainingCheckinManagerProps> = ({
  queue,
  registrationList,
  staffList,
  forms,
  formSubmissions,
  onCheckIn, 
  onUpdateTicketStatus, 
  onClearQueue, 
  onUpdateRegistration,
  onBatchAddStaff,
  onManageForm
}) => {
  const [activeTab, setActiveTab] = useState<'ON_SITE' | 'MASTER' | 'DASHBOARD'>('ON_SITE');

  // Local state for On-Site records (separate from Master List)
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>(() => {
    const saved = localStorage.getItem('onSiteRecords');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist On-Site records
  useEffect(() => {
    localStorage.setItem('onSiteRecords', JSON.stringify(onSiteRecords));
  }, [onSiteRecords]);

  // --- Statistics Calculation (Combines both lists for overview) ---
  const stats = useMemo(() => {
    const allRecords = [...registrationList, ...onSiteRecords];
    // Remove duplicates based on ID just in case
    const uniqueRecords = Array.from(new Map(allRecords.map(item => [item.id, item])).values());

    const totalRegistrations = uniqueRecords.length;
    const totalOnSite = onSiteRecords.length;

    // Gender Logic
    const males = uniqueRecords.filter(r => r.gender === '男');
    const females = uniqueRecords.filter(r => r.gender === '女');
    const unknownGender = uniqueRecords.filter(r => r.gender !== '男' && r.gender !== '女');

    // --- Metrics ---
    const todayStr = new Date().toDateString();
    const todayRegistrations = uniqueRecords.filter(r => 
      new Date(r.submissionTime).toDateString() === todayStr
    ).length;

    // Verification Rate: Records with ID Card present (Length > 4 as a basic check)
    const verifiedCount = uniqueRecords.filter(r => r.idCard && r.idCard.length > 4).length;
    const verificationRate = totalRegistrations > 0 ? (verifiedCount / totalRegistrations * 100).toFixed(0) : "0";

    // Availability Distribution
    let totalManDays = 0;
    const daysDistribution: Record<string, number> = { '1天': 0, '2天': 0, '3天': 0, '4天': 0, '5天+': 0 };

    uniqueRecords.forEach(r => {
      try {
        const avail = JSON.parse(r.availability || '{}');
        const dayCount = Object.values(avail).filter(v => v === 'FULL' || v === 'AM' || v === 'PM').length;

        totalManDays += dayCount;

        // Bucket count
        if (dayCount === 1) daysDistribution['1天']++;
        else if (dayCount === 2) daysDistribution['2天']++;
        else if (dayCount === 3) daysDistribution['3天']++;
        else if (dayCount === 4) daysDistribution['4天']++;
        else if (dayCount >= 5) daysDistribution['5天+']++;
      } catch (e) {}
    });

    const avgDays = totalRegistrations > 0 ? (totalManDays / totalRegistrations).toFixed(1) : "0.0";

    const genderData = [
      { name: '男生', value: males.length, color: '#3b82f6' },
      { name: '女生', value: females.length, color: '#ec4899' },
      { name: '未知', value: unknownGender.length, color: '#9ca3af' },
    ].filter(d => d.value > 0);

    const availabilityChartData = Object.entries(daysDistribution).map(([name, value]) => ({ name, value }));

    return {
      totalRegistrations,
      totalOnSite,
      todayRegistrations,
      verificationRate,
      avgDays,
      genderData,
      availabilityChartData,
      maleCount: males.length,
      femaleCount: females.length
    };
  }, [registrationList, onSiteRecords]);

  return (
    <div className="space-y-6 animate-fade-in h-full flex flex-col">
      {/* Header & Tabs */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 shrink-0">
        <div>
          <h1 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            <ClipboardList className="text-indigo-600" /> 报名管理
          </h1>
          <p className="text-gray-500 text-sm mt-1">
            实时监控现场报名数据
          </p>
        </div>

        <div className="flex bg-white p-1.5 rounded-xl shadow-sm border border-gray-200">
          <button
            onClick={() => setActiveTab('ON_SITE')}
            className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
              activeTab === 'ON_SITE' 
                ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' 
                : 'text-gray-600 hover:bg-gray-50'
            }`}
          >
            <FileText size={16} /> 现场报名
          </button>
          <button
            onClick={() => setActiveTab('MASTER')}
            className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
              activeTab === 'MASTER' 
                ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' 
                : 'text-gray-600 hover:bg-gray-50'
            }`}
          >
            <UserPlus size={16} /> 汇总名单
          </button>
          <button
            onClick={() => setActiveTab('DASHBOARD')}
            className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${
              activeTab === 'DASHBOARD' 
                ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200' 
                : 'text-gray-600 hover:bg-gray-50'
            }`}
          >
            <LayoutDashboard size={16} /> 数据看板
          </button>
        </div>
      </div>

      {/* Content Area */}
      {/* Use consistent container for all tabs to prevent layout shift */}
      <div className="flex-1 min-h-0 flex flex-col overflow-y-scroll custom-scrollbar">

        {/* TAB 1: ON_SITE REGISTRATION */}
        {activeTab === 'ON_SITE' && (
           <StaffRegistration 
              records={onSiteRecords} 
              onUpdateRecords={setOnSiteRecords}
              groups={[]} 
              onBatchAddStaff={onBatchAddStaff}
              existingStaffList={staffList}
              forms={forms}
              formSubmissions={formSubmissions}
              onManageForm={onManageForm}
              displayMode="MASTER" 
              allowFormSync={true} 
              allowExcelImport={false} 
              allowManualEntry={false} 
           />
        )}

        {/* TAB 2: MASTER LIST */}
        {activeTab === 'MASTER' && (
           <StaffRegistration 
              records={registrationList} 
              onUpdateRecords={onUpdateRegistration}
              groups={[]} 
              onBatchAddStaff={onBatchAddStaff}
              existingStaffList={staffList}
              forms={forms}
              formSubmissions={formSubmissions}
              onManageForm={onManageForm}
              displayMode="MASTER"
              allowFormSync={false} 
              allowExcelImport={true}
              allowManualEntry={true}
           />
        )}

        {/* TAB 3: DASHBOARD */}
        {activeTab === 'DASHBOARD' && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300 pb-10">

            {/* Overview Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-4">
              {/* Total Card */}
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                 <div>
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">总报名人数</p>
                    <h2 className="text-2xl font-black text-gray-800">{stats.totalRegistrations}</h2>
                 </div>
                 <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center">
                    <Users size={20} />
                 </div>
              </div>

              {/* On-Site Card (Requested) */}
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
                 <div>
                    <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">新增现场报名</p>
                    <h2 className="text-2xl font-black text-gray-800">{stats.totalOnSite}</h2>
                 </div>
                 <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                    <MapPin size={20} />
                 </div>
              </div>

              {/* Today Card */}
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-purple-100 flex items-center justify-between relative overflow-hidden">
                 <div className="relative z-10">
                    <p className="text-purple-400 text-xs font-bold uppercase tracking-wider mb-1">今日新增 (全渠道)</p>
                    <h2 className="text-2xl font-black text-purple-600">+{stats.todayRegistrations}</h2>
                 </div>
                 <div className="w-10 h-10 bg-purple-50 text-purple-500 rounded-xl flex items-center justify-center relative z-10">
                    <UserPlus size={20} />
                 </div>
                 <div className="absolute right-0 bottom-0 h-1 bg-purple-400 w-full opacity-20"></div>
              </div>

              {/* Verification Card (Requested) */}
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-green-100 flex items-center justify-between">
                 <div>
                    <p className="text-green-600/60 text-xs font-bold uppercase tracking-wider mb-1">信息核验率</p>
                    <h2 className="text-2xl font-black text-green-600">{stats.verificationRate}%</h2>
                 </div>
                 <div className="w-10 h-10 bg-green-50 text-green-600 rounded-xl flex items-center justify-center">
                    <ShieldCheck size={20} />
                 </div>
              </div>

              {/* Average Days Card */}
              <div className="bg-white p-5 rounded-2xl shadow-sm border border-orange-100 flex items-center justify-between relative overflow-hidden">
                 <div className="relative z-10">
                    <p className="text-orange-400 text-xs font-bold uppercase tracking-wider mb-1">人均可用天数</p>
                    <h2 className="text-2xl font-black text-orange-600">{stats.avgDays} <span className="text-sm text-gray-400 font-normal">天</span></h2>
                 </div>
                 <div className="w-10 h-10 bg-orange-50 text-orange-500 rounded-xl flex items-center justify-center relative z-10">
                    <CalendarRange size={20} />
                 </div>
                 <div className="absolute right-0 bottom-0 h-1 bg-orange-400 w-full opacity-20"></div>
              </div>
            </div>

            {/* Charts Section */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

               {/* Availability Distribution Bar Chart */}
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                     <BarChart3 size={18} className="text-orange-500" /> 可工作天数分布 (人数统计)
                  </h3>
                  <div className="h-64">
                     <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={stats.availabilityChartData} margin={{top: 10, right: 30, left: 0, bottom: 0}}>
                           <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                           <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} dy={10} />
                           <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} allowDecimals={false} />
                           <Tooltip 
                              cursor={{fill: '#f9fafb'}}
                              contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} 
                           />
                           <Bar dataKey="value" name="人数" fill="#f97316" radius={[4, 4, 0, 0]} barSize={40} />
                        </BarChart>
                     </ResponsiveContainer>
                  </div>
               </div>

               {/* Gender Distribution Pie */}
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                  <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                     <PieChart size={18} className="text-indigo-500" /> 报名人员性别分布
                  </h3>
                  <div className="h-64">
                     <ResponsiveContainer width="100%" height="100%">
                        <RePieChart>
                           <Pie
                              data={stats.genderData}
                              cx="50%"
                              cy="50%"
                              innerRadius={60}
                              outerRadius={80}
                              paddingAngle={5}
                              dataKey="value"
                              cornerRadius={6}
                           >
                              {stats.genderData.map((entry, index) => (
                                 <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={0} />
                              ))}
                           </Pie>
                           <Tooltip contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} />
                           <Legend verticalAlign="bottom" height={36} iconType="circle" />
                        </RePieChart>
                     </ResponsiveContainer>
                  </div>
               </div>

               {/* Text Summary */}
               <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col justify-center lg:col-span-2">
                  <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                     <TrendingUp size={18} className="text-green-500" /> 数据洞察
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                     <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-3">
                           <div className="p-2 bg-blue-100 text-blue-600 rounded-lg"><User size={16} /></div>
                           <div>
                              <p className="text-sm font-bold text-gray-700">男生数量</p>
                              <p className="text-xs text-gray-400">占比 {stats.totalRegistrations > 0 ? Math.round((stats.maleCount/stats.totalRegistrations)*100) : 0}%</p>
                           </div>
                        </div>
                        <span className="text-xl font-bold text-gray-800">{stats.maleCount}</span>
                     </div>

                     <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-3">
                           <div className="p-2 bg-pink-100 text-pink-600 rounded-lg"><User size={16} /></div>
                           <div>
                              <p className="text-sm font-bold text-gray-700">女生数量</p>
                              <p className="text-xs text-gray-400">占比 {stats.totalRegistrations > 0 ? Math.round((stats.femaleCount/stats.totalRegistrations)*100) : 0}%</p>
                           </div>
                        </div>
                        <span className="text-xl font-bold text-gray-800">{stats.femaleCount}</span>
                     </div>

                     <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                        <div className="flex items-center gap-3">
                           <div className="p-2 bg-orange-100 text-orange-600 rounded-lg"><CalendarRange size={16} /></div>
                           <div>
                              <p className="text-sm font-bold text-gray-700">全勤意向 (5天+)</p>
                              <p className="text-xs text-gray-400">稳定核心力量</p>
                           </div>
                        </div>
                        <span className="text-xl font-bold text-gray-800">
                           {stats.availabilityChartData.find(d => d.name === '5天+')?.value || 0}
                        </span>
                     </div>
                  </div>
               </div>

            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default TrainingCheckinManager;
]]></content>
