    <content><![CDATA[
import React, { useState, useMemo, useEffect } from 'react';
import { 
  LayoutDashboard, 
  UserPlus, 
  Users, 
  ClipboardList, 
  TrendingUp,
  CalendarRange,
  PieChart,
  User,
  FileText,
  ShieldCheck,
  MapPin,
  BarChart3
} from 'lucide-react';
import { QueueTicket, RegistrationRecord, Staff, FormTemplate, FormSubmission } from '../types';
import StaffRegistration from './StaffRegistration';
import { ResponsiveContainer, PieChart as RePieChart, Pie, Cell, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

interface TrainingCheckinManagerProps {
  queue: QueueTicket[];
  registrationList: RegistrationRecord[];
  staffList: Staff[]; // Needed for legacy compatibility in sub-components
  forms: FormTemplate[];
  formSubmissions: FormSubmission[];
  onCheckIn: (staffId: string) => void;
  onUpdateTicketStatus: (ticketId: string, status: QueueTicket['status']) => void;
  onClearQueue: () => void;
  onUpdateRegistration: (records: RegistrationRecord[]) => void;
  onBatchAddStaff: (staffList: Staff[]) => void;
  onManageForm?: (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => void;
}

const TrainingCheckinManager: React.FC<TrainingCheckinManagerProps> = ({
  queue,
  registrationList,
  staffList,
  forms,
  formSubmissions,
  onCheckIn, 
  onUpdateTicketStatus, 
  onClearQueue, 
  onUpdateRegistration,
  onBatchAddStaff,
  onManageForm
}) => {
  const [activeTab, setActiveTab] = useState<'ON_SITE' | 'MASTER' | 'DASHBOARD'>('ON_SITE');

  // Local state for On-Site records (separate from Master List)
  const [onSiteRecords, setOnSiteRecords] = useState<RegistrationRecord[]>(() => {
    const saved = localStorage.getItem('onSiteRecords');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist On-Site records
  useEffect(() => {
    localStorage.setItem('onSiteRecords', JSON.stringify(onSiteRecords));
  }, [onSiteRecords]);

  // --- Statistics Calculation (Combines both lists for overview) ---
  const stats = useMemo(() => {
    const allRecords = [...registrationList, ...onSiteRecords];
    // Remove duplicates based on ID just in case
    const uniqueRecords = Array.from(new Map(allRecords.map(item => [item.id, item])).values());

    const totalRegistrations = uniqueRecords.length;
    const totalOnSite = onSiteRecords.length;

    // Gender Logic
    const males = uniqueRecords.filter(r => r.gender === '男');
    const females = uniqueRecords.filter(r => r.gender === '女');
    const unknownGender = uniqueRecords.filter(r => r.gender !== '男' && r.gender !== '女');

    // --- Metrics ---
    const todayStr = new Date().toDateString();
    const todayRegistrations = uniqueRecords.filter(r => 
      new Date(r.submissionTime).toDateString() === todayStr
    ).length;

    // Verification Rate: Records with ID Card present (Length > 4 as a basic check)
    const verifiedCount = uniqueRecords.filter(r => r.idCard && r.idCard.length > 4).length;
    const verificationRate = totalRegistrations > 0 ? (verifiedCount / totalRegistrations * 100).toFixed(0) : "0";

    // Availability Distribution
    let totalManDays = 0;
    const daysDistribution: Record<string, number> = { '1天': 0, '2天': 0, '3天': 0, '4天': 0, '5天+': 0 };

    uniqueRecords.forEach(r => {
      try {
        const avail = JSON.parse(r.availability || '{}');
        const dayCount = Object.values(avail).filter(v => v === 'FULL' || v === 'AM' || v === 'PM').length;

        totalManDays += dayCount;

        // Bucket count
        if (dayCount === 1) daysDistribution['1天']++;
        else if (dayCount === 2) daysDistribution['2天']++;
        else if (dayCount === 3) daysDistribution['3天']++;
        else if (dayCount === 4) daysDistribution['4天']++;
        else if (dayCount >= 5) daysDistribution['5天+']++;
      } catch (e) {}
    });

    const avgDays = totalRegistrations > 0 ? (totalManDays / totalRegistrations).toFixed(1) : "0.0";

    const genderData = [
      { name: '男生', value: males.length, color: '#3b82f6' },
      { name: '女生', value: females.length, color: '#ec4899' },
      { name: '未知', value: unknownGender.length, color: '#9ca3af' },
    ].filter(d => d.value > 0);

    const availabilityChartData = Object.entries(daysDistribution).map(([name, value]) => ({ name, value }));

    return {
      totalRegistrations,
      totalOnSite,
      todayRegistrations,
      verificationRate,
      avgDays,
      genderData,
      availabilityChartData,
      maleCount: males.length,
      femaleCount: females.length
    };
  }, [registrationList, onSiteRecords]);

