                     <button onClick={() => setActiveTab('outsourced')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'outsourced' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <Briefcase size={20} /> <span className="font-medium">分组与编外</span>
                     </button>
                     <button onClick={() => setActiveTab('form_manager')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'form_manager' || activeTab === 'form_designer' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                      <FileText size={20} /> <span className="font-medium">表单中心</span>
