                  <button onClick={() => setSidebarOpen(false)} className="text-slate-400 hover:text-white"><X size={24} /></button>
               </div>

               <nav className="flex-1 space-y-1 overflow-y-auto">
                 {/* Re-using same nav logic for mobile */}
                 {session.role === 'ADMIN' ? (
                   <>
                      <p className="px-4 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">管理中心</p>
                      <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">工作台</button>
                      <button onClick={() => { setActiveTab('training_checkin'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">报名管理</button>
                      <button onClick={() => { setActiveTab('outsourced'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">分组与编外</button>
                      <button onClick={() => { setActiveTab('form_manager'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">表单中心</button>
                      <button onClick={() => { setActiveTab('settings'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">系统设置</button>
                   </>
                 ) : (
                   <>
                      <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">我的主页</button>
                      {isLeader && (
                        <>
                          <p className="px-4 mt-4 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">组长管理</p>
                          <button onClick={() => { setActiveTab('reports'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">考勤记录</button>
                          <button onClick={() => { setActiveTab('announcements'); setSidebarOpen(false); }} className="w-full text-left px-4 py-3 text-slate-300 hover:text-white hover:bg-slate-800 rounded-xl">发布公告</button>
                        </>
                      )}
                   </>
                 )}
               </nav>

               <div className="pt-4 mt-4 border-t border-slate-800">
                  <button onClick={handleLogout} className="flex items-center gap-2 text-slate-400 hover:text-white w-full px-2 py-2">
                     <LogOut size={18} /> 退出登录
                  </button>
               </div>
            </div>
          </div>
        )}

        {/* Content */}
        <div className={`flex-1 overflow-x-hidden ${isFullScreen ? '' : 'p-4 lg:p-8'}`}>
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;
