        let visibleGroups = groups;
        if (session?.role === 'USER' && session.staff) {
           // For leaders: Only show groups where they are a leader
           const leaderGroupIds = session.staff.roles
             .filter(r => r.isLeader)
             .map(r => r.groupId);
           visibleGroups = groups.filter(g => leaderGroupIds.includes(g.id));
        }

        return <AttendanceReports 
          staffList={staffList} 
          groups={visibleGroups} 
          allRecords={attendanceRecords} 
          // If the user only has one group, we can optionally lock it, but giving the dropdown with 1 item is also fine.
          // fixedGroupId is no longer strictly necessary with the new filter logic, but helps UX if single group.
          fixedGroupId={visibleGroups.length === 1 ? visibleGroups[0].id : undefined} 
        />;
      case 'registration':
